import React from "react";
import { useNavigate } from "react-router-dom";

const Layout = ({ children, pageTitle = "NexaLearn LMS" }) => {
  const navigate = useNavigate();

  const handleLogout = () => {
    localStorage.removeItem("role");
    navigate("/");
  };

  const userRole = localStorage.getItem("role");

  return (
    <div
      style={{
        minHeight: "100vh",
        backgroundColor: "#f5f7fa",
        fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif",
      }}
    >
      {/* HEADER */}
      <header
        style={{
          background: "linear-gradient(90deg, #a71010, #7a0c0c)",
          padding: "15px 30px",
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          boxShadow: "0 4px 12px rgba(0,0,0,0.1)",
        }}
      >
        {/* Left Section */}
        <div style={{ display: "flex", alignItems: "center", gap: "15px" }}>
          <img
            src="https://upload.wikimedia.org/wikipedia/en/thumb/7/7a/Koneru_Lakshmaiah_University_logo.png/220px-Koneru_Lakshmaiah_University_logo.png"
            alt="Nexa Logo"
            style={{ height: "45px" }}
          />
          <h1
            style={{
              color: "#fff",
              fontWeight: "700",
              fontSize: "1.3rem",
              margin: 0,
              textTransform: "uppercase",
              letterSpacing: "1px",
            }}
          >
            {pageTitle}
          </h1>
        </div>

        {/* Right Section */}
        {userRole && (
          <div style={{ display: "flex", alignItems: "center", gap: "20px" }}>
            <span
              style={{
                color: "#fff",
                fontWeight: "500",
                fontSize: "0.95rem",
                backgroundColor: "rgba(255,255,255,0.2)",
                padding: "6px 12px",
                borderRadius: "20px",
              }}
            >
              {userRole.toUpperCase()}
            </span>

            <button
              onClick={handleLogout}
              style={{
                backgroundColor: "#ffffff",
                color: "#a71010",
                border: "none",
                padding: "8px 16px",
                borderRadius: "20px",
                fontWeight: "600",
                cursor: "pointer",
                transition: "0.3s",
              }}
            >
              Logout
            </button>
          </div>
        )}
      </header>

      {/* MAIN CONTENT */}
      <main
        style={{
          maxWidth: "1200px",
          margin: "40px auto",
          backgroundColor: "#ffffff",
          boxShadow: "0 10px 30px rgba(0,0,0,0.08)",
          borderRadius: "10px",
          padding: "40px",
          minHeight: "75vh",
        }}
      >
        {children}
      </main>
    </div>
  );
};

export default Layout;
